import React, { useState, useEffect, useRef } from 'react';
import './HookWatch.css';

const HookWatch = () => {
  const [time, setTime] = useState(0);
  const [isRunning, setIsRunning] = useState(false);
  const [laps, setLaps] = useState([]);
  const intervalRef = useRef(null);

  useEffect(() => {
    if (isRunning) {
      intervalRef.current = setInterval(() => {
        setTime(prevTime => prevTime + 10);
      }, 10);
    } else {
      clearInterval(intervalRef.current);
    }

    return () => clearInterval(intervalRef.current);
  }, [isRunning]);

  const formatTime = (milliseconds) => {
    const totalSeconds = Math.floor(milliseconds / 1000);
    const minutes = Math.floor(totalSeconds / 60);
    const seconds = totalSeconds % 60;
    const ms = Math.floor((milliseconds % 1000) / 10);

    return `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}.${ms.toString().padStart(2, '0')}`;
  };

  const handleStart = () => {
    setIsRunning(true);
  };

  const handleStop = () => {
    setIsRunning(false);
  };

  const handleReset = () => {
    setIsRunning(false);
    setTime(0);
    setLaps([]);
  };

  const handleLap = () => {
    if (isRunning && time > 0) {
      setLaps([...laps, time]);
    }
  };

  const handleClearLaps = () => {
    setLaps([]);
  };

  return (
    <div className="hookwatch-container">
      <div className="hookwatch-header">
        <h1>HookWatch</h1>
        <p>Precision Stopwatch</p>
      </div>

      <div className="time-display">
        <div className="time-value">
          {formatTime(time)}
        </div>
        <div className="time-label">
          {isRunning ? 'Running' : 'Stopped'}
        </div>
      </div>

      <div className="controls">
        {!isRunning ? (
          <button 
            className="btn btn-start" 
            onClick={handleStart}
            disabled={time > 0 && laps.length === 0}
          >
            {time === 0 ? 'Start' : 'Resume'}
          </button>
        ) : (
          <button className="btn btn-stop" onClick={handleStop}>
            Stop
          </button>
        )}

        <button className="btn btn-lap" onClick={handleLap} disabled={!isRunning}>
          Lap
        </button>

        <button className="btn btn-reset" onClick={handleReset}>
          Reset
        </button>
      </div>

      {laps.length > 0 && (
        <div className="laps-section">
          <div className="laps-header">
            <h3>Lap Times</h3>
            <button className="btn-clear-laps" onClick={handleClearLaps}>
              Clear All
            </button>
          </div>
          <div className="laps-list">
            {laps.map((lapTime, index) => (
              <div key={index} className="lap-item">
                <span className="lap-number">Lap {index + 1}</span>
                <span className="lap-time">{formatTime(lapTime)}</span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default HookWatch;
